```typescript
export type WarehouseState =
  | { status: "empty" }
  | { status: "operational"; id: string; code: string; activeBins: number }
  | { status: "decommissioned"; id: string };

export type WarehouseCommand =
  | { type: "open"; id: string; code: string }
  | { type: "expand"; addedBins: number }
  | { type: "decommission" };

export type WarehouseEvent =
  | { type: "WarehouseOpened"; id: string; code: string }
  | { type: "WarehouseExpanded"; addedBins: number }
  | { type: "WarehouseDecommissioned" };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const warehouseDecider: Decider<WarehouseCommand, WarehouseEvent, WarehouseState> = {
  initialState: { status: "empty" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "empty") throw new DomainError("ALREADY_OPEN");
        return [{ type: "WarehouseOpened", id: c.id, code: c.code }];
      case "expand":
        if (s.status !== "operational") throw new DomainError("NOT_OPERATIONAL");
        if (c.addedBins <= 0) throw new DomainError("NON_POSITIVE");
        return [{ type: "WarehouseExpanded", addedBins: c.addedBins }];
      case "decommission":
        if (s.status !== "operational") throw new DomainError("NOT_OPERATIONAL");
        if (s.activeBins > 0) throw new DomainError("BINS_STILL_ACTIVE");
        return [{ type: "WarehouseDecommissioned" }];
      default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "WarehouseOpened":
        return { status: "operational", id: e.id, code: e.code, activeBins: 0 };
      case "WarehouseExpanded":
        if (s.status !== "operational") return s;
        return { ...s, activeBins: s.activeBins + e.addedBins };
      case "WarehouseDecommissioned":
        if (s.status !== "operational") return s;
        return { status: "decommissioned", id: s.id };
      default: { const _n: never = e; return s; }
    }
  },
};
