```typescript
export type BinState =
  | { status: "free" }
  | { status: "allocated"; id: string; sku: string; level: number }
  | { status: "retired"; id: string };

export type BinCommand =
  | { type: "allocate"; id: string; sku: string }
  | { type: "restock"; qty: number }
  | { type: "retire" };

export type BinEvent =
  | { type: "BinAllocated"; id: string; sku: string }
  | { type: "BinRestocked"; qty: number }
  | { type: "BinRetired" };

export class BinError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const binDecider: Decider<BinCommand, BinEvent, BinState> = {
  initialState: { status: "free" },
  decide(c, s) {
    switch (c.type) {
      case "allocate":
        if (s.status !== "free") throw new BinError("NOT_FREE");
        if (c.sku.length === 0) throw new BinError("SKU_REQUIRED");
        return [{ type: "BinAllocated", id: c.id, sku: c.sku }];
      case "restock":
        if (s.status !== "allocated") throw new BinError("NOT_ALLOCATED");
        if (c.qty <= 0) throw new BinError("NON_POSITIVE");
        return [{ type: "BinRestocked", qty: c.qty }];
      case "retire":
        if (s.status === "retired") throw new BinError("ALREADY_RETIRED");
        return [{ type: "BinRetired" }];
      default: { const _n: never = c; throw new BinError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "BinAllocated":
        return { status: "allocated", id: e.id, sku: e.sku, level: 0 };
      case "BinRestocked":
        if (s.status !== "allocated") return s;
        return { ...s, level: s.level + e.qty };
      case "BinRetired":
        if (s.status === "retired") return s;
        const id = s.status === "allocated" ? s.id : "";
        return { status: "retired", id };
      default: { const _n: never = e; return s; }
    }
  },
};
```

A Decider locks all business rules inside `decide` and treats `evolve` as a total fold. `decide(command, state)` either produces events or throws a typed error; `evolve(state, event)` can assume every incoming event is already legal because `decide` guards the write path. That separation makes rehydration from the event stream deterministic.

```typescript
export type LotState =
  | { status: "none" }
  | { status: "active"; id: string; sku: string; qty: number }
  | { status: "quarantined"; id: string; sku: string; qty: number; reason: string };

export type LotCommand =
  | { type: "create"; id: string; sku: string; qty: number }
  | { type: "quarantine"; reason: string }
  | { type: "release" };

export type LotEvent =
  | { type: "LotCreated"; id: string; sku: string; qty: number }
  | { type: "LotQuarantined"; reason: string }
  | { type: "LotReleased" };

export class LotError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const lotDecider: Decider<LotCommand, LotEvent, LotState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "create":
        if (s.status !== "none") throw new LotError("EXISTS");
        if (c.qty <= 0) throw new LotError("QTY_INVALID");
        return [{ type: "LotCreated", id: c.id, sku: c.sku, qty: c.qty }];
      case "quarantine":
        if (s.status !== "active") throw new LotError("NOT_ACTIVE");
        return [{ type: "LotQuarantined", reason: c.reason }];
      case "release":
        if (s.status !== "quarantined") throw new LotError("NOT_QUARANTINED");
        return [{ type: "LotReleased" }];
      default: { const _n: never = c; throw new LotError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "LotCreated":
        return { status: "active", id: e.id, sku: e.sku, qty: e.qty };
      case "LotQuarantined":
        if (s.status !== "active") return s;
        return { status: "quarantined", id: s.id, sku: s.sku, qty: s.qty, reason: e.reason };
      case "LotReleased":
        if (s.status !== "quarantined") return s;
        return { status: "active", id: s.id, sku: s.sku, qty: s.qty };
      default: { const _n: never = e; return s; }
    }
  },
};
