```typescript
export type PackingState =
  | { status: "idle" }
  | { status: "packing"; id: string; orderId: string; items: ReadonlyArray<string> }
  | { status: "sealed"; id: string; orderId: string; items: ReadonlyArray<string>; sealedAt: string };

export type PackingCommand =
  | { type: "start"; id: string; orderId: string }
  | { type: "scan-item"; sku: string }
  | { type: "seal"; at: string };

export type PackingEvent =
  | { type: "PackingStarted"; id: string; orderId: string }
  | { type: "PackingItemScanned"; sku: string }
  | { type: "PackingSealed"; at: string };

export class PackingError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const packingDecider: Decider<PackingCommand, PackingEvent, PackingState> = {
  initialState: { status: "idle" },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "idle") throw new PackingError("IN_PROGRESS");
        return [{ type: "PackingStarted", id: c.id, orderId: c.orderId }];
      case "scan-item":
        if (s.status !== "packing") throw new PackingError("NOT_PACKING");
        if (c.sku.length === 0) throw new PackingError("SKU_EMPTY");
        return [{ type: "PackingItemScanned", sku: c.sku }];
      case "seal":
        if (s.status !== "packing") throw new PackingError("NOT_PACKING");
        if (s.items.length === 0) throw new PackingError("EMPTY_PACK");
        return [{ type: "PackingSealed", at: c.at }];
      default: { const _n: never = c; throw new PackingError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "PackingStarted":
        return { status: "packing", id: e.id, orderId: e.orderId, items: [] };
      case "PackingItemScanned":
        if (s.status !== "packing") return s;
        return { ...s, items: [...s.items, e.sku] };
      case "PackingSealed":
        if (s.status !== "packing") return s;
        return { status: "sealed", id: s.id, orderId: s.orderId, items: s.items, sealedAt: e.at };
      default: { const _n: never = e; return s; }
    }
  },
};
```

A Decider is a pure triple — `initialState`, `decide`, `evolve`. Each transition is validated in `decide`; `evolve` just folds events into state.

```typescript
export type CrateState =
  | { status: "empty" }
  | { status: "loaded"; id: string; weight: number }
  | { status: "sealed"; id: string; weight: number; sealedAt: string }
  | { status: "dispatched"; id: string; to: string };

export type CrateCommand =
  | { type: "load"; id: string; weight: number }
  | { type: "seal"; at: string }
  | { type: "dispatch"; to: string };

export type CrateEvent =
  | { type: "CrateLoaded"; id: string; weight: number }
  | { type: "CrateSealed"; at: string }
  | { type: "CrateDispatched"; to: string };

export class CrateError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const crateDecider: Decider<CrateCommand, CrateEvent, CrateState> = {
  initialState: { status: "empty" },
  decide(c, s) {
    switch (c.type) {
      case "load":
        if (s.status !== "empty") throw new CrateError("ALREADY_LOADED");
        if (c.weight <= 0) throw new CrateError("WEIGHT_INVALID");
        return [{ type: "CrateLoaded", id: c.id, weight: c.weight }];
      case "seal":
        if (s.status !== "loaded") throw new CrateError("NOT_LOADED");
        return [{ type: "CrateSealed", at: c.at }];
      case "dispatch":
        if (s.status !== "sealed") throw new CrateError("NOT_SEALED");
        return [{ type: "CrateDispatched", to: c.to }];
      default: { const _n: never = c; throw new CrateError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "CrateLoaded":
        return { status: "loaded", id: e.id, weight: e.weight };
      case "CrateSealed":
        if (s.status !== "loaded") return s;
        return { status: "sealed", id: s.id, weight: s.weight, sealedAt: e.at };
      case "CrateDispatched":
        if (s.status !== "sealed") return s;
        return { status: "dispatched", id: s.id, to: e.to };
      default: { const _n: never = e; return s; }
    }
  },
};
