```typescript
export type BinEvent =
  | { type: "BinAllocated"; binId: string; sku: string }
  | { type: "BinRestocked"; binId: string; sku: string; qty: number }
  | { type: "BinPicked"; binId: string; sku: string; qty: number }
  | { type: "BinRetired"; binId: string; sku: string; remaining: number };

export interface BinInventoryView {
  readonly totals: Readonly<Record<string, number>>;
}

export const emptyView: BinInventoryView = { totals: {} };

function bump(totals: Readonly<Record<string, number>>, sku: string, delta: number): Readonly<Record<string, number>> {
  const current = totals[sku] ?? 0;
  const next = current + delta;
  if (next <= 0) {
    const { [sku]: _dropped, ...rest } = totals;
    void _dropped;
    return rest;
  }
  return { ...totals, [sku]: next };
}

export function project(view: BinInventoryView, event: BinEvent): BinInventoryView {
  switch (event.type) {
    case "BinAllocated":
      return view;
    case "BinRestocked":
      return { totals: bump(view.totals, event.sku, event.qty) };
    case "BinPicked":
      return { totals: bump(view.totals, event.sku, -event.qty) };
    case "BinRetired":
      if (event.remaining === 0) return view;
      return { totals: bump(view.totals, event.sku, -event.remaining) };
    default: { const _n: never = event; return view; }
  }
}
```

```typescript
export type PackingEvent =
  | { type: "PackingStarted"; id: string; orderId: string }
  | { type: "PackingItemScanned"; id: string; sku: string }
  | { type: "PackingSealed"; id: string; at: string }
  | { type: "PackingAborted"; id: string; reason: string };

export interface ThroughputView {
  readonly open: number;
  readonly sealed: number;
  readonly aborted: number;
  readonly seen: Readonly<Record<string, "open" | "sealed" | "aborted">>;
}

export const emptyView: ThroughputView = { open: 0, sealed: 0, aborted: 0, seen: {} };

export function project(view: ThroughputView, event: PackingEvent): ThroughputView {
  switch (event.type) {
    case "PackingStarted":
      if (view.seen[event.id]) return view;
      return { ...view, open: view.open + 1, seen: { ...view.seen, [event.id]: "open" } };
    case "PackingItemScanned":
      return view;
    case "PackingSealed": {
      if (view.seen[event.id] !== "open") return view;
      return { ...view, open: view.open - 1, sealed: view.sealed + 1, seen: { ...view.seen, [event.id]: "sealed" } };
    }
    case "PackingAborted": {
      if (view.seen[event.id] !== "open") return view;
      return { ...view, open: view.open - 1, aborted: view.aborted + 1, seen: { ...view.seen, [event.id]: "aborted" } };
    }
    default: { const _n: never = event; return view; }
  }
}
