```typescript
interface ContainerV1 {
  id: string;
  seal: string;
  weight: number;
}

interface ContainerV2 {
  id: string;
  seal: string;
  grossWeight: number;
  tareWeight: number;
}

interface ContainerV3 {
  id: string;
  seal: string;
  grossWeight: number;
  tareWeight: number;
  origin: string;
  route: ReadonlyArray<string>;
}

export type CurrentContainer = ContainerV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3 as const;

function v1Tov2(prev: ContainerV1): ContainerV2 {
  return { id: prev.id, seal: prev.seal, grossWeight: prev.weight, tareWeight: 0 };
}

function v2Tov3(prev: ContainerV2): ContainerV3 {
  return { ...prev, origin: "UNKNOWN", route: [] };
}

function isCurrent(value: unknown): value is CurrentContainer {
  if (typeof value !== "object" || value === null) return false;
  const v = value as Partial<CurrentContainer>;
  return typeof v.id === "string"
    && typeof v.seal === "string"
    && typeof v.grossWeight === "number"
    && typeof v.tareWeight === "number"
    && typeof v.origin === "string"
    && Array.isArray(v.route);
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentContainer> {
  let current: { version: number; state: unknown } = { version: snap.version, state: snap.state };
  if (current.version === 1) {
    current = { version: 2, state: v1Tov2(current.state as ContainerV1) };
  }
  if (current.version === 2) {
    current = { version: 3, state: v2Tov3(current.state as ContainerV2) };
  }
  if (current.version !== CURRENT_VERSION) {
    throw new Error(`Unsupported snapshot version ${current.version}`);
  }
  if (!isCurrent(current.state)) {
    throw new Error("Upgraded snapshot does not match CurrentContainer shape");
  }
  return { version: CURRENT_VERSION, state: current.state };
}
```

Replaying millions of events on every boot is expensive, so we persist periodic snapshots. But the aggregate shape drifts over time. A versioned snapshot carries the version it was written at; on load, upgraders compose `v1 -> v2 -> ... -> current` so the in-memory state always matches the code. The event log is untouched.

```typescript
interface PickListV1 {
  id: string;
  picker: string;
  items: ReadonlyArray<string>;
}

interface PickListV2 {
  id: string;
  picker: string;
  items: ReadonlyArray<{ sku: string; qty: number }>;
}

interface PickListV3 {
  id: string;
  picker: string;
  wave: string;
  items: ReadonlyArray<{ sku: string; qty: number }>;
}

export type CurrentPickList = PickListV3;
export const CURRENT_VERSION = 3 as const;

export interface Snapshot<S> { readonly version: number; readonly state: S; }

function v1Tov2(prev: PickListV1): PickListV2 {
  return { id: prev.id, picker: prev.picker, items: prev.items.map((sku) => ({ sku, qty: 1 })) };
}
function v2Tov3(prev: PickListV2): PickListV3 {
  return { ...prev, wave: "LEGACY" };
}

function assertCurrent(value: unknown): asserts value is CurrentPickList {
  const v = value as Partial<CurrentPickList>;
  if (typeof v?.id !== "string" || typeof v?.picker !== "string" || typeof v?.wave !== "string" || !Array.isArray(v?.items)) {
    throw new Error("Not a CurrentPickList");
  }
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentPickList> {
  let state: unknown = snap.state;
  let version = snap.version;
  if (version === 1) { state = v1Tov2(state as PickListV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as PickListV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`Unknown version ${version}`);
  assertCurrent(state);
  return { version: CURRENT_VERSION, state };
}
