```typescript
import { Effect } from "effect";

export type BinEvent =
  | { type: "BinAllocated"; sku: string }
  | { type: "BinRestocked"; qty: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: ReadonlyArray<BinEvent>; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<BinEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<{ kind: "ok"; revision: bigint } | { kind: "conflict"; actual: bigint | null }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly actual: bigint | null) {
    super(`Concurrency conflict on ${stream} at ${String(actual)}`);
    this.name = "ConcurrencyConflict";
  }
}

export const appendBinEvents = (
  store: EventStore,
  stream: string,
  newEvents: ReadonlyArray<BinEvent>,
) =>
  Effect.gen(function* () {
    const slice = yield* Effect.promise(() => store.readStream(stream));
    const expected: ExpectedRevision = slice.revision ?? "no_stream";
    const outcome = yield* Effect.promise(() =>
      store.appendToStream(stream, newEvents, { expectedRevision: expected }),
    );
    if (outcome.kind === "conflict") {
      return yield* Effect.fail(new ConcurrencyConflict(stream, outcome.actual));
    }
    return outcome.revision;
  });
```

Read the current revision, pass it as `expectedRevision`, and map any conflict signal from the store onto a typed domain error. This keeps retries explicit at the call site.

