  store: EventStore,
  stream: string,
  events: ReadonlyArray<OutboundEvent>,
): Promise<bigint> {
  const slice = await store.readStream(stream);
  const expectedRevision: ExpectedRevision = slice.revision ?? "no_stream";
  const res = await store.appendToStream(stream, events, { expectedRevision });
  if (!res.ok) throw new ConcurrencyConflict(`conflict on ${stream} actual=${String(res.actual)}`);
  return res.revision;
