export type LotState =
  | { status: "none" }
  | { status: "active"; id: string; sku: string; qty: number };

export type LotCommand =
  | { type: "create"; id: string; sku: string; qty: number }
  | { type: "consume"; qty: number };

export type LotEvent =
  | { type: "LotCreated"; id: string; sku: string; qty: number }
  | { type: "LotConsumed"; qty: number };

export class LotError extends Error {}

export const initialState: LotState = { status: "none" };

export function evolve(s: LotState, e: LotEvent): LotState {
  switch (e.type) {
    case "LotCreated": return { status: "active", id: e.id, sku: e.sku, qty: e.qty };
    case "LotConsumed":
      if (s.status !== "active") return s;
      return { ...s, qty: s.qty - e.qty };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: LotCommand, s: LotState): LotEvent[] {
  switch (c.type) {
    case "create":
      if (s.status !== "none") throw new LotError("EXISTS");
      return [{ type: "LotCreated", id: c.id, sku: c.sku, qty: c.qty }];
    case "consume":
      if (s.status !== "active") throw new LotError("NOT_ACTIVE");
      if (c.qty > s.qty) throw new LotError("INSUFFICIENT");
      return [{ type: "LotConsumed", qty: c.qty }];
    default: { const _n: never = c; throw new LotError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<LotEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<LotEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export async function handleLotCommand(
  streamName: string,
  command: LotCommand,
  store: EventStore,
): Promise<bigint> {
  const slice = await store.readStream(streamName);
  const state = slice.events.reduce(evolve, initialState);
  const out = decide(command, state);
  if (out.length === 0) return slice.revision ?? -1n;
  return store.appendToStream(streamName, out, { expectedRevision: slice.revision ?? "no_stream" });
}
