export const initialState: PackingState = { status: "idle" };

export function evolve(s: PackingState, e: PackingEvent): PackingState {
  switch (e.type) {
    case "PackingStarted": return { status: "packing", id: e.id, items: 0 };
    case "PackingItemScanned":
      if (s.status !== "packing") return s;
      return { ...s, items: s.items + 1 };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: PackingCommand, s: PackingState): PackingEvent[] {
  switch (c.type) {
    case "start":
      if (s.status !== "idle") throw new PackingError("BUSY");
      return [{ type: "PackingStarted", id: c.id }];
    case "scan":
      if (s.status !== "packing") throw new PackingError("NOT_PACKING");
      return [{ type: "PackingItemScanned", sku: c.sku }];
    default: { const _n: never = c; throw new PackingError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<PackingEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<PackingEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

