export type BinEvent =
  | { type: "BinRestocked"; binId: string; sku: string; qty: number; revision: bigint }
  | { type: "BinPicked"; binId: string; sku: string; qty: number; revision: bigint };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface RestockView {
  readonly bySku: Readonly<Record<string, number>>;
}

export interface ReadModelStore {
  load(): Promise<RestockView>;
  save(view: RestockView): Promise<void>;
}

export function project(view: RestockView, event: BinEvent): RestockView {
  switch (event.type) {
    case "BinRestocked":
      return { bySku: { ...view.bySku, [event.sku]: (view.bySku[event.sku] ?? 0) + event.qty } };
    case "BinPicked":
      return { bySku: { ...view.bySku, [event.sku]: (view.bySku[event.sku] ?? 0) - event.qty } };
    default: { const _n: never = event; return view; }
  }
}

export async function runSubscription(
  name: string,
  events: AsyncIterable<BinEvent>,
  readModel: ReadModelStore,
  checkpoints: CheckpointStore,
): Promise<void> {
  let view = await readModel.load();
  const _start = (await checkpoints.read(name)) ?? -1n;
  void _start;
  async function main(): Promise<void> {
    for await (const event of events) {
      view = project(view, event);
      await readModel.save(view);
      await checkpoints.write(name, event.revision);
    }
  }
  await main();
}
```

Persist the stream position only AFTER the read model has been updated. If the process dies between them you re-apply the last event on restart, which is safe because the projection is idempotent.

