export type OutboundState =
  | { status: "empty" }
  | { status: "prepared"; id: string; destination: string; crates: number };

export type OutboundCommand =
  | { type: "prepare"; id: string; destination: string }
  | { type: "load-crate"; crateId: string };

export type OutboundEvent =
  | { type: "OutboundPrepared"; id: string; destination: string }
  | { type: "OutboundCrateLoaded"; crateId: string };

export class OutboundError extends Error {}

const initialState: OutboundState = { status: "empty" };

function evolve(s: OutboundState, e: OutboundEvent): OutboundState {
  switch (e.type) {
    case "OutboundPrepared": return { status: "prepared", id: e.id, destination: e.destination, crates: 0 };
    case "OutboundCrateLoaded":
      if (s.status !== "prepared") return s;
      return { ...s, crates: s.crates + 1 };
    default: { const _n: never = e; return s; }
  }
}

function decide(c: OutboundCommand, s: OutboundState): OutboundEvent[] {
  switch (c.type) {
    case "prepare":
      if (s.status !== "empty") throw new OutboundError("PREPARED");
      return [{ type: "OutboundPrepared", id: c.id, destination: c.destination }];
    case "load-crate":
      if (s.status !== "prepared") throw new OutboundError("NOT_PREPARED");
      return [{ type: "OutboundCrateLoaded", crateId: c.crateId }];
    default: { const _n: never = c; throw new OutboundError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: ReadonlyArray<OutboundEvent>; revision: bigint | null }>;
  appendToStream(s: string, events: ReadonlyArray<OutboundEvent>, opts: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

// Read side — independent shape; eventually consistent with the event store.
export interface OutboundSummary {
  readonly id: string;
  readonly destination: string;
  readonly crateCount: number;
}

export interface ReadStore {
  get(id: string): Promise<OutboundSummary | null>;
}

export async function handleCommand(stream: string, command: OutboundCommand, store: EventStore): Promise<bigint> {
  const slice = await store.readStream(stream);
  const state = slice.events.reduce(evolve, initialState);
  const out = decide(command, state);
  if (out.length === 0) return slice.revision ?? -1n;
  return store.appendToStream(stream, out, { expectedRevision: slice.revision ?? "no_stream" });
}

export async function queryView(id: string, read: ReadStore): Promise<OutboundSummary | null> {
  return read.get(id);
}
