  | { type: "DispatchOutbound"; outboundId: string; crateId: string };

export function react(event: ReactableEvent): SagaCommand | null {
  switch (event.type) {
    case "OutboundPrepared":
      return { type: "StartPacking", outboundId: event.outboundId };
    case "PackingSealed":
      return { type: "DispatchOutbound", outboundId: event.outboundId, crateId: event.crateId };
    case "OutboundDispatched":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
