  handle(streamName: string, command: C): Promise<void>;
}

export async function dispatch(events: ReadonlyArray<ReactableEvent>, handler: CommandHandler<SagaCommand>): Promise<void> {
  for (const event of events) {
    const cmd = react(event);
    if (cmd === null) continue;
    await handler.handle(`outbound-${cmd.outboundId}`, cmd);
  }
}
