A saga is a pure reactor: it consumes domain events from multiple aggregates and returns the next command to dispatch. State, if any, lives in the event streams themselves. Because `react` is a function of the inbound event, the whole workflow is replayable and testable without infrastructure.

```typescript
export type ReactableEvent =
  | { type: "LotReleased"; lotId: string; sku: string }
  | { type: "SerialIssued"; serialId: string; lotId: string; sku: string }
  | { type: "InventoryRecorded"; serialId: string };

export type SagaCommand =
  | { type: "IssueSerial"; lotId: string; sku: string }
  | { type: "RecordInventory"; serialId: string };

export function react(event: ReactableEvent): SagaCommand | null {
  switch (event.type) {
    case "LotReleased":
      return { type: "IssueSerial", lotId: event.lotId, sku: event.sku };
    case "SerialIssued":
      return { type: "RecordInventory", serialId: event.serialId };
    case "InventoryRecorded":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface CommandHandler<C> {
  handle(stream: string, command: C): Promise<void>;
}

export async function runSaga(
  events: AsyncIterable<ReactableEvent>,
  handler: CommandHandler<SagaCommand>,
): Promise<void> {
  async function main(): Promise<void> {
    for await (const event of events) {
      const next = react(event);
      if (next === null) continue;
      const stream = next.type === "IssueSerial" ? `lot-${next.lotId}` : `serial-${next.serialId}`;
      await handler.handle(stream, next);
    }
  }
  await main();
}
