export type BinState =
  | { status: "free" }
  | { status: "staged"; id: string; sku: string }
  | { status: "released"; id: string };

export type BinCommand =
  | { type: "stage"; id: string; sku: string }
  | { type: "release"; reason: string };

export type BinEvent =
  | { type: "BinStaged"; id: string; sku: string }
  | { type: "BinReleased"; reason: string };

export class InvariantError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "InvariantError";
  }
}

export function decide(command: BinCommand, state: BinState): BinEvent[] {
  switch (command.type) {
    case "stage":
      if (state.status !== "free") throw new InvariantError("NOT_FREE");
      if (command.sku.length === 0) throw new InvariantError("SKU_REQUIRED");
      return [{ type: "BinStaged", id: command.id, sku: command.sku }];
    case "release":
      if (state.status !== "staged") throw new InvariantError("NOT_STAGED");
      return [{ type: "BinReleased", reason: command.reason }];
    default: {
      const _never: never = command;
      throw new InvariantError("UNKNOWN_COMMAND");
    }
  }
}
