export type ContainerState =
  | { status: "empty" }
  | { status: "open"; id: string; seal: string }
  | { status: "sealed"; id: string; seal: string }
  | { status: "dispatched"; id: string; destination: string };

export type ContainerCommand =
  | { type: "register"; id: string; seal: string }
  | { type: "seal" }
  | { type: "dispatch"; destination: string };

export type ContainerEvent =
  | { type: "ContainerRegistered"; id: string; seal: string }
  | { type: "ContainerSealed" }
  | { type: "ContainerDispatched"; destination: string };

export class ContainerError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const containerDecider: Decider<ContainerCommand, ContainerEvent, ContainerState> = {
  initialState: { status: "empty" },
  decide(c, s) {
    switch (c.type) {
      case "register":
        if (s.status !== "empty") throw new ContainerError("EXISTS");
        return [{ type: "ContainerRegistered", id: c.id, seal: c.seal }];
      case "seal":
        if (s.status !== "open") throw new ContainerError("NOT_OPEN");
        return [{ type: "ContainerSealed" }];
      case "dispatch":
        if (s.status !== "sealed") throw new ContainerError("NOT_SEALED");
        return [{ type: "ContainerDispatched", destination: c.destination }];
      default: { const _n: never = c; throw new ContainerError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ContainerRegistered":
        return { status: "open", id: e.id, seal: e.seal };
      case "ContainerSealed":
        if (s.status !== "open") return s;
        return { status: "sealed", id: s.id, seal: s.seal };
      case "ContainerDispatched":
        if (s.status !== "sealed") return s;
        return { status: "dispatched", id: s.id, destination: e.destination };
      default: { const _n: never = e; return s; }
    }
  },
};
